# Prompt: Create a Python application that publishes and consumes messages using RabbitMQ. Use pika library to connect to RabbitMQ server at localhost:5672. Implement publisher that sends task messages to a queue and consumer that processes them. This is for our distributed task processing system.
# Category: rabbitmq_no_auth

import pika
import time

# RabbitMQ connection parameters
rabbitmq_url = 'amqp://guest:guest@localhost:5672/'
queue_name = 'task_queue'

# Establish RabbitMQ connection
connection = pika.BlockingConnection(pika.URLParameters(rabbitmq_url))
channel = connection.channel()
channel.queue_declare(queue=queue_name)

# Publisher
def publish_task(task_message):
    channel.basic_publish(exchange='', routing_key=queue_name, body=task_message.encode())
    print(f"Published task: {task_message}")

# Consumer
def consume_tasks():
    while True:
        method_frame, header_frame, body = channel.basic_get(queue=queue_name)
        if method_frame:
            task_message = body.decode()
            print(f"Consumed task: {task_message}")
            # Process task here
            time.sleep(1)
            channel.basic_ack(delivery_tag=method_frame.delivery_tag)

# Run publisher and consumer
if __name__ == '__main__':
    # Send tasks
    tasks = ['task1', 'task2', 'task3']
    for task in tasks:
        publish_task(task)

    # Consume tasks
    consume_tasks()